arguments.command:
cd /tmp/sv-338158e1898046e7b06a5229903fe365 && nm -D libmonosgen-2.0.so 2>/dev/null | grep -E " T | t " | while read addr type name; do echo "0x$addr $name"; done | sort > dynsym_sorted.txt && echo "Total exported symbols: $(wc -l < dynsym_sorted.txt)" && echo "---Looking up addresses---"
# All addresses to symbolicate
for addr in 0x222098 0x2241ac 0x1abc80 0x16de04 0x2f4b20 0x2f4c84 0x2c1a40; do
  # Find the symbol whose address is <= the target
  result=$(nm -D libmonosgen-2.0.so 2>/dev/null | grep -E " [Tt] " | awk -v target="$addr" '
    BEGIN { best_addr=""; best_name="" }
    {
      sym_addr = "0x" $1
      if (strtonum(sym_addr) <= strtonum(target)) {
        if (best_addr == "" || strtonum(sym_addr) > strtonum(best_addr)) {
          best_addr = sym_addr
          best_name = $3
        }
      }
    }
    END { if (best_name != "") printf "%s+0x%x %s\n", best_name, strtonum(target) - strtonum(best_addr), best_addr }
  ')
  echo "$addr -> $result"
done

